+}
+
+#[inline]
+pub fn atanf(x: f32) -> f32 {
+    libm::atanf(x)
+}
+
+#[inline]
+pub fn atan2f(y: f32, x: f32) -> f32 {
+    libm::atan2f(y, x)
+}
+
+// --- Exponential / logarithmic ---
+
+#[inline]
+pub fn expf(x: f32) -> f32 {
+    libm::expf(x)
+}
+
+#[inline]
+pub fn logf(x: f32) -> f32 {
