+    libm::log10f(x)
+}
+
+#[inline]
+pub fn powf(base: f32, exponent: f32) -> f32 {
+    libm::powf(base, exponent)
+}
+
+// --- Float utilities ---
+
+#[inline]
+pub fn sqrtf(x: f32) -> f32 {
+    libm::sqrtf(x)
+}
+
+#[inline]
+pub fn fabsf(x: f32) -> f32 {
+    libm::fabsf(x)
+}
+
+#[inline]
+pub fn ceilf(x: f32) -> f32 {
+    libm::ceilf(x)
+}
+
